CREATE TABLE IF NOT EXISTS public.admin_logs ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), admin_id UUID REFERENCES public.profiles(id) ON DELETE SET NULL, target_user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE, action TEXT NOT NULL, reason TEXT NOT NULL, comments TEXT, created_at TIMESTAMPTZ DEFAULT NOW() ); ALTER TABLE public.admin_logs ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "Admins can insert logs" ON public.admin_logs; DROP POLICY IF EXISTS "Admins can view logs" ON public.admin_logs; CREATE POLICY "Admins can insert logs" ON public.admin_logs FOR INSERT WITH CHECK (get_my_role() = 'admin'); CREATE POLICY "Admins can view logs" ON public.admin_logs FOR SELECT USING (get_my_role() = 'admin'); ALTER PUBLICATION supabase_realtime ADD TABLE jobs; ALTER PUBLICATION supabase_realtime ADD TABLE profiles; ALTER PUBLICATION supabase_realtime ADD TABLE messages;
